(function() {
    const CHECK_INTERVAL = 1 * 60 * 1000; 
    let lastSoldItemsStr = "";
    function checkJishouStatus() {
        if (!window.pomelo) return;
        window.pomelo.request("area.playerHandler.getPlayerJishouList", null, function(res) {
            if (res.code === 200 && res.data) {
                let soldItems = res.data.filter(function(item) { return item.isSell; });
                if (soldItems.length > 0) {
                    let currentSoldItemsStr = soldItems.map(function(item) { return item.id; }).sort().join(",");
                    if (currentSoldItemsStr !== lastSoldItemsStr) {
                        lastSoldItemsStr = currentSoldItemsStr;
                        let names = [];
                        soldItems.forEach(function(item) {
                            let name = item.goodsName || item.name || "寄售商品";
                            names.push("<span style='color:#ffff00;'>" + name + "</span> / 已卖出！");
                        });
                        showHtmlNotification(names.join("<br/>"));
                    }
                } else {
                    lastSoldItemsStr = "";
                }
            }
        });
    }
    function showHtmlNotification(message) {
        let bubbleId = "jishou-html-notify-bubble";
        let bubble = document.getElementById(bubbleId);
        if (bubble) bubble.remove();
        bubble = document.createElement("div");
        bubble.id = bubbleId;
        bubble.style.cssText = "position: fixed; top: 15px; left: 21%; background-color: rgba(40, 20, 10, 0.95); color: #4cfa09; border: 2px solid #ff0000; padding: 15px 30px 15px 20px; border-radius: 8px; font-size: 16px; font-family: 'SimSun', '宋体', sans-serif; font-weight: bold; z-index: 9999999; box-shadow: 0 4px 15px rgba(0,0,0,0.8); cursor: pointer; transition: opacity 0.3s ease, transform 0.3s ease; text-align: left; user-select: none; pointer-events: auto; transform: translateY(-20px); opacity: 0; line-height: 1.6;";
        bubble.innerHTML = "<div style='position:absolute; top:5px; right:10px; color:#fff; font-size:14px; padding:2px 5px; background:rgba(255,0,0,0.6); border-radius:4px;'>关闭 X</div>" + 
                           "<div style='color:#fff; font-size:18px; margin-bottom:8px; text-align:center; border-bottom:1px solid #666; padding-bottom:5px;'>💰 寄售售出提醒 💰</div>" + 
                           message;
        bubble.onclick = function(e) {
            e.stopPropagation();
            e.preventDefault();
            bubble.style.opacity = "0";
            bubble.style.transform = "translateY(-20px)";
            setTimeout(function() { bubble.remove(); }, 300);
        };
        document.body.appendChild(bubble);
        requestAnimationFrame(function() {
            bubble.style.opacity = "1";
            bubble.style.transform = "translateY(0)";
        });
    }
    if (window.jishouTimerHtml) clearInterval(window.jishouTimerHtml);
    window.jishouTimerHtml = setInterval(checkJishouStatus, CHECK_INTERVAL);
    checkJishouStatus();
    console.log("%c[寄售监控-网页版] 插件已部署成功并启动！", "color:#4cfa09; font-size:14px; font-weight:bold; background:#000; padding:5px;");
})();
